    if (mode & CRYPTO_LOCK) {
        lock_cs[type]->Lock();
        lock_count[type]++;
    } else {
        lock_cs[type]->Unlock();
    }
}

unsigned long beos_thread_id(void)
{
    unsigned long ret;

    ret = (unsigned long)find_thread(NULL);
